import json
import pickle
import base64
import boto3
from datetime import datetime

dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table('webhook_events')

def lambda_handler(event, context):
    try:
        body = json.loads(event['body']) if isinstance(event.get('body'), str) else event.get('body', {})
        
        partner_id = body.get('partner_id')
        event_type = body.get('event_type')
        user_action = body.get('user_action')
        timestamp = body.get('timestamp', datetime.utcnow().isoformat())
        
        if not all([partner_id, event_type, user_action]):
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Missing required fields'})
            }
        
        pickled_data = pickle.dumps(user_action)
        encoded_data = base64.b64encode(pickled_data).decode('utf-8')
        
        item = {
            'event_id': f"{partner_id}_{timestamp}",
            'partner_id': partner_id,
            'event_type': event_type,
            'serialized_data': encoded_data,
            'timestamp': timestamp,
            'processed': False
        }
        
        table.put_item(Item=item)
        
        decoded_data = base64.b64decode(encoded_data)
        deserialized_action = pickle.loads(decoded_data)
        
        result = process_user_action(deserialized_action, event_type)
        
        table.update_item(
            Key={'event_id': item['event_id']},
            UpdateExpression='SET processed = :val',
            ExpressionAttributeValues={':val': True}
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Event processed successfully',
                'event_id': item['event_id'],
                'result': result
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }

def process_user_action(action_data, event_type):
    if event_type == 'user_signup':
        return handle_signup(action_data)
    elif event_type == 'user_purchase':
        return handle_purchase(action_data)
    elif event_type == 'user_activity':
        return handle_activity(action_data)
    else:
        return {'status': 'unknown_event_type'}

def handle_signup(data):
    user_id = data.get('user_id')
    email = data.get('email')
    return {'status': 'signup_processed', 'user_id': user_id}

def handle_purchase(data):
    user_id = data.get('user_id')
    amount = data.get('amount')
    items = data.get('items', [])
    return {'status': 'purchase_processed', 'user_id': user_id, 'total': amount}

def handle_activity(data):
    user_id = data.get('user_id')
    activity_type = data.get('activity_type')
    return {'status': 'activity_logged', 'user_id': user_id, 'type': activity_type}